// Modal UI for adding/removing options
function ManageItemsModal({ items, defaultItems, onAdd, onRemove, onClose, onSave, show, label }) {
  const [localItems, setLocalItems] = useState(items);

  useEffect(() => { setLocalItems(items); }, [items, show]);

  const handleAdd = () => {
    const newItem = window.prompt(`Add new ${label}:`);
    if (
      newItem && 
      !defaultItems.concat(localItems).map(v => v.trim().toLowerCase()).includes(newItem.trim().toLowerCase())
    ) {
      setLocalItems([...localItems, newItem.trim()]);
    }
  };

  const handleRemove = (index) => {
    setLocalItems(localItems.filter((_, i) => i !== index));
  };

  const handleSave = () => { onSave(localItems); onClose(); };
  if (!show) return null;

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h3>Manage {label}s</h3>
        <ul className="modal-list">
          {localItems.map((item, idx) => (
            <li key={item} className="modal-list-item">
              {item}
              <button
                className="modal-btn-delete"
                onClick={() => handleRemove(idx)}
                title={`Delete ${label}`}
              >
                <FiTrash size={14} />
              </button>
            </li>
          ))}
        </ul>
        <div className="modal-actions">
          <button className="modal-btn-add" onClick={handleAdd}>Add</button>
          <button className="modal-btn-save" onClick={handleSave}>Save</button>
          <button className="modal-btn-cancel" onClick={onClose}>Cancel</button>
        </div>
      </div>
      <style jsx>{`
        .modal-overlay {
          position: fixed;
          top:0;left:0;right:0;bottom:0;
          background: rgba(0,0,0,0.15);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 99;
        }
        .modal {
          background: #fff;
          padding: 24px 20px;
          border-radius: 12px;
          box-shadow: 0 0 32px rgba(102, 126, 234, 0.16);
          min-width: 280px;
        }
        .modal h3 {
          margin-top: 0;
          margin-bottom: 14px;
          font-size: 1.2rem;
          font-weight: 600;
        }
        .modal-list { list-style:none; margin:0; padding:0; max-height:120px; overflow-y:auto;}
        .modal-list-item {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 7px 0;
          border-bottom: 1px solid #f0f4f8;
        }
        .modal-btn-delete {
          background: none; border:none; color:#e53e3e; cursor:pointer; margin-left:8px;
        }
        .modal-actions {
          margin-top: 16px;
          display: flex;
          gap: 8px;
        }
        .modal-btn-add, .modal-btn-save, .modal-btn-cancel {
          padding: 7px 15px;
          font-weight: 500;
          border:none;
          border-radius:8px;
          cursor:pointer;
        }
        .modal-btn-add {
          background: #bee3f8; color: #276749;
        }
        .modal-btn-add:hover {
          background: #90cdf4;
        }
        .modal-btn-save {
          background: #c6f6d5; color: #276749;
        }
        .modal-btn-save:hover {
          background: #9ae6b4;
        }
        .modal-btn-cancel {
          background: #fed7d7; color: #c53030;
        }
        .modal-btn-cancel:hover {
          background: #feb2b2;
        }
      `}</style>
    </div>
  );
}

export default function Users() {
  const defaultNewUser = {
    firstName: '', lastName: '', email: '',
    role: 'Developer', department: 'Engineering', active: true,
    language: 'English', mobileNumber: '', dateFormat: 'YYYY-MM-DD',
    passwordResetNeeded: false, profileFile: null,
  };

  const defaultRoles = ['Admin', 'Manager', 'Developer', 'Reporter'];
  const defaultDepartments = ['Engineering', 'Sales', 'HR', 'Marketing'];
  const [customRoles, setCustomRoles] = useState([]);
  const [customDepartments, setCustomDepartments] = useState([]);

  const [users, setUsers] = useState([]);
  const [newUserForm, setNewUserForm] = useState(defaultNewUser);
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [searchTerm, setSearchTerm] = useState('');
  const [error, setError] = useState(null);

  // Modal state
  const [showRoleModal, setShowRoleModal] = useState(false);
  const [showDeptModal, setShowDeptModal] = useState(false);

  const {
    firstName, lastName, email, role, department, active, language, mobileNumber, dateFormat, passwordResetNeeded, profileFile
  } = newUserForm;

  useEffect(() => {
    const fetchUsers = async () => {
      try { setUsers(await listUsers()); }
      catch (err) { setError('Failed to load users'); }
    };
    fetchUsers();
  }, []);

  const handleNewUserChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    setNewUserForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (type === 'file' ? files[0] : value)
    }));
  };

  const handleEditChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    setEditForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (type === 'file' ? files[0] : value)
    }));
  };

  const create = async () => {
    if (!firstName.trim() || !lastName.trim() || !email.trim()) {
      setError('First Name, Last Name, and Email are required.');
      return;
    }
    try {
      const newUser = {
        id: uuidv4(), ...newUserForm,
        name: `${firstName.trim()} ${lastName.trim()}`,
        profileFile: profileFile ? { name: profileFile.name, size: profileFile.size } : null
      };
      await addUser(newUser);
      setUsers(await listUsers());
      setNewUserForm(defaultNewUser);
      setError(null);
    } catch {
      setError('Failed to add user');
    }
  };

  const startEdit = (u) => { setEditingId(u.id); setEditForm({ ...u }); setError(null); };

  const cancelEdit = () => { setEditingId(null); setEditForm({}); setError(null); };

  const saveEdit = async (id) => {
    if (!editForm.firstName.trim() || !editForm.lastName.trim() || !editForm.email.trim()) {
      setError('First Name, Last Name, and Email cannot be empty.');
      return;
    }
    try {
      const updatedUser = {
        ...editForm, name: `${editForm.firstName.trim()} ${editForm.lastName.trim()}`,
        profileFile: editForm.profileFile && editForm.profileFile.name ?
          { name: editForm.profileFile.name, size: editForm.profileFile.size } :
          editForm.profileFile
      };
      await updateUser(updatedUser);
      setUsers(await listUsers());
      cancelEdit();
      setError(null);
    } catch {
      setError('User not found or failed to update');
    }
  };

  const remove = async (id) => {
    try {
      await deleteUser(id);
      setUsers(await listUsers());
      setError(null);
    } catch {
      setError('User not found or failed to delete');
    }
  };

  const filteredUsers = users.filter(user => {
    const searchLower = searchTerm.toLowerCase();
    return (
      (user.name && user.name.toLowerCase().includes(searchLower)) ||
      (user.firstName && user.firstName.toLowerCase().includes(searchLower)) ||
      (user.lastName && user.lastName.toLowerCase().includes(searchLower)) ||
      (user.email && user.email.toLowerCase().includes(searchLower)) ||
      (user.role && user.role.toLowerCase().includes(searchLower)) ||
      (user.department && user.department.toLowerCase().includes(searchLower))
    );
  });

  const getRoleColor = (roleOrDepartment) => {
    const colors = {
      'admin': 'role-admin',
      'manager': 'role-manager',
      'developer': 'role-developer',
      'reporter': 'role-reporter',
      'engineering': 'role-developer',
      'sales': 'role-sales',
      'hr': 'role-hr',
      'marketing': 'role-marketing'
    };
    return colors[roleOrDepartment.toLowerCase()] || '';
  };

  return (
    <div className="users-container">
      {/* Global background for full page */}
      <style jsx global>{`
        body { background: #D8F7FA; min-height: 100vh; }
      `}</style>

      <div className="users-header">
        <h1 className="users-title">User Management System 🧑‍💼</h1>
        <p className="users-subtitle">Manage your team members, roles, and administrative settings.</p>
        {error && <p className="error-message">{error}</p>}
      </div>

      <div className="users-grid">
        {/* User creation form */}
        <div className="users-form-card glassmorphism" aria-labelledby="users-form-title">
          <div className="card-header">
            <h2 id="users-form-title" className="card-title">
              <FiUserPlus className="icon-spacing" /> Add New User
            </h2>
          </div>
          <div className="form-grid-expanded">
            <div className="input-group">
              <label className="input-label" style={{display:'flex', alignItems:'center', gap:'5px'}}>
                Role
                <button type="button" className="add-btn-icon" aria-label="Add Role" onClick={() => setShowRoleModal(true)}
                  style={{
                    marginLeft: '4px', border: 'none', background: 'none', cursor: 'pointer', padding: 0, display: 'flex', alignItems: 'center'
                  }}>
                  <FiPlus />
                </button>
              </label>
              <select className="modern-select" name="role" value={role} onChange={handleNewUserChange}>
                {[...defaultRoles, ...customRoles].map(r => (
                  <option key={r}>{r}</option>
                ))}
              </select>
            </div>
            <div className="input-group">
              <label className="input-label" style={{display:'flex', alignItems:'center', gap:'5px'}}>
                Department
                <button type="button" className="add-btn-icon" aria-label="Add Department" onClick={() => setShowDeptModal(true)}
                  style={{
                    marginLeft: '4px', border: 'none', background: 'none', cursor: 'pointer', padding: 0, display: 'flex', alignItems: 'center'
                  }}>
                  <FiPlus />
                </button>
              </label>
              <select className="modern-select" name="department" value={department} onChange={handleNewUserChange}>
                {[...defaultDepartments, ...customDepartments].map(d => (
                  <option key={d}>{d}</option>
                ))}
              </select>
            </div>
            <div className="input-group">
              <label className="input-label">First Name *</label>
              <input className="modern-input" name="firstName" value={firstName} onChange={handleNewUserChange} placeholder="First Name" />
            </div>
            <div className="input-group">
              <label className="input-label">Last Name *</label>
              <input className="modern-input" name="lastName" value={lastName} onChange={handleNewUserChange} placeholder="Last Name" />
            </div>
            <div className="input-group">
              <label className="input-label">Email Address *</label>
              <input className="modern-input" name="email" value={email} onChange={handleNewUserChange} placeholder="Email Address" type="email" />
            </div>
            <div className="input-group">
              <label className="input-label">Mobile Number</label>
              <input className="modern-input" name="mobileNumber" value={mobileNumber} onChange={handleNewUserChange} placeholder="Mobile Number" type="tel" />
            </div>
            <div className="input-group">
              <label className="input-label">Preferred Language</label>
              <select className="modern-select" name="language" value={language} onChange={handleNewUserChange}>
                <option>English</option>
                <option>Spanish</option>
                <option>French</option>
                <option>German</option>
              </select>
            </div>
            <div className="input-group">
              <label className="input-label">Date Format</label>
              <select className="modern-select" name="dateFormat" value={dateFormat} onChange={handleNewUserChange}>
                <option>DD/MM/YYYY</option>
              </select>
            </div>
            <div className="input-group checkbox-group">
              <label className="input-label">User Status</label>
              <label className="checkbox-label">
                <input type="checkbox" name="active" checked={active} onChange={handleNewUserChange} />
                <span className="checkbox-text">{active ? 'Active' : 'Inactive'}</span>
              </label>
            </div>
            <div className="input-group checkbox-group">
              <label className="input-label">Password Reset</label>
              <label className="checkbox-label">
                <input type="checkbox" name="passwordResetNeeded" checked={passwordResetNeeded} onChange={handleNewUserChange} />
                <span className="checkbox-text">Reset on next login</span>
              </label>
            </div>
          </div>
          <button className="create-btn" onClick={create}>
            <FiUserPlus className="btn-icon" />
            Create User
          </button>
          <ManageItemsModal
            show={showRoleModal}
            label="Role"
            items={customRoles}
            defaultItems={defaultRoles}
            onAdd={() => {}}
            onRemove={() => {}}
            onClose={() => setShowRoleModal(false)}
            onSave={(items) => setCustomRoles(items)}
          />
          <ManageItemsModal
            show={showDeptModal}
            label="Department"
            items={customDepartments}
            defaultItems={defaultDepartments}
            onAdd={() => {}}
            onRemove={() => {}}
            onClose={() => setShowDeptModal(false)}
            onSave={(items) => setCustomDepartments(items)}
          />
        </div>

        {/* User list section */}
        {/* ...rest of your unchanged user list section and styles... */}
        <div className="users-list-card glassmorphism" aria-labelledby="users-list-title">
          <div className="card-header">
            <h2 id="users-list-title" className="card-title">
              Team Members ({filteredUsers.length})
            </h2>
            <div className="search-container">
              <FiSearch className="search-icon" />
              <input
                type="text"
                className="search-input"
                placeholder="Search users..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <div className="table-container">
            <table className="modern-table" role="table" aria-label="Users table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Department</th>
                  <th>Role</th>
                  <th>Active</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map(u => (
                  <tr key={u.id} className={editingId === u.id ? 'editing-row' : ''}>
                    {editingId === u.id ? (
                      <>
                        <td>
                          <input
                            className="edit-input"
                            name="firstName"
                            value={editForm.firstName || ''}
                            onChange={handleEditChange}
                            placeholder="First Name"
                          />
                          <input
                            className="edit-input"
                            name="lastName"
                            value={editForm.lastName || ''}
                            onChange={handleEditChange}
                            placeholder="Last Name"
                            style={{marginTop: '5px'}}
                          />
                        </td>
                        <td>
                          <input
                            className="edit-input"
                            name="email"
                            value={editForm.email || ''}
                            onChange={handleEditChange}
                          />
                        </td>
                        <td>
                          <select
                            className="edit-select"
                            name="department"
                            value={editForm.department || defaultNewUser.department}
                            onChange={handleEditChange}
                          >
                            {[...defaultDepartments, ...customDepartments].map(d => (
                              <option key={d}>{d}</option>
                            ))}
                          </select>
                        </td>
                        <td>
                          <select
                            className="edit-select"
                            name="role"
                            value={editForm.role || defaultNewUser.role}
                            onChange={handleEditChange}
                          >
                            {[...defaultRoles, ...customRoles].map(r => (
                              <option key={r}>{r}</option>
                            ))}
                          </select>
                        </td>
                        <td>
                          <input
                            type="checkbox"
                            name="active"
                            checked={editForm.active || false}
                            onChange={handleEditChange}
                          />
                        </td>
                        <td>
                          <div className="action-buttons">
                            <button onClick={() => saveEdit(u.id)} className="btn-success" title="Save">
                              <FiCheck />
                            </button>
                            <button onClick={cancelEdit} className="btn-cancel" title="Cancel">
                              <FiX />
                            </button>
                          </div>
                        </td>
                      </>
                    ) : (
                      <>
                        <td>
                          <div className="user-info">
                            <div className="avatar">{u.firstName ? u.firstName.charAt(0) : (u.name ? u.name.charAt(0) : 'U')}</div>
                            <span>{u.firstName || u.name} {u.lastName}</span>
                            <div className="file-indicator" title={u.profileFile ? `File: ${u.profileFile.name}` : 'No file'}>
                              {u.profileFile && '📁'}
                            </div>
                          </div>
                        </td>
                        <td>{u.email}</td>
                        <td>
                          <span className={`role-badge ${getRoleColor(u.department || 'engineering')}`}>
                            {u.department}
                          </span>
                        </td>
                        <td>
                          <span className={`role-badge ${getRoleColor(u.role || 'developer')}`}>
                            {u.role}
                          </span>
                        </td>
                        <td>
                          <span className={`status-dot ${u.active ? 'status-active' : 'status-inactive'}`} title={u.active ? 'Active' : 'Inactive'}></span>
                        </td>
                        <td>
                          <div className="action-buttons">
                            <button onClick={() => startEdit(u)} className="btn-edit" title="Edit">
                              <FiEdit2 />
                            </button>
                            <button onClick={() => remove(u.id)} className="btn-delete" title="Delete">
                              <FiTrash2 />
                            </button>
                          </div>
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredUsers.length === 0 && (
              <div className="empty-state">
                <p>No users found{searchTerm && ` matching "${searchTerm}"`}</p>
              </div>
            )}
          </div>
        </div>
      </div>
      {/* ...CSS for add-btn-icon remains... */}
      <style jsx>{`
        .add-btn-icon {
          font-size: 1.1em;
          margin-left: 3px;
          color: #4e54c8;
          padding: 0;
          background: none;
          border: none;
          cursor: pointer;
          display: flex;
          align-items: center;
        }
        .add-btn-icon:hover {
          color: #1e2e9a;
          background: #e3eefa;
        }
      `}</style>
    </div>
  );
}
